import React, { useEffect, useState, useMemo } from 'react';
import { UserProfile } from '../types';

interface Props {
  profile: UserProfile;
}

const LifeClock: React.FC<Props> = ({ profile }) => {
  const [timeLeft, setTimeLeft] = useState<{ years: number; days: number; hours: number; minutes: number; seconds: number } | null>(null);
  const [totalSecondsLeft, setTotalSecondsLeft] = useState(0);

  // Calculate the projected end date based on birthdate + 78 years + accumulated seconds
  const deathDate = useMemo(() => {
    const start = new Date(profile.birthDate);
    // Add 78 years
    const end = new Date(start);
    end.setFullYear(start.getFullYear() + profile.lifeExpectancyYears);
    // Add accumulated seconds (bonus/penalty)
    end.setSeconds(end.getSeconds() + profile.accumulatedSeconds);
    return end;
  }, [profile]);

  useEffect(() => {
    const calculateTime = () => {
      const now = new Date();
      const difference = deathDate.getTime() - now.getTime();

      if (difference <= 0) {
        setTimeLeft({ years: 0, days: 0, hours: 0, minutes: 0, seconds: 0 });
        setTotalSecondsLeft(0);
        return;
      }

      setTotalSecondsLeft(Math.floor(difference / 1000));

      const years = Math.floor(difference / (1000 * 60 * 60 * 24 * 365.25));
      const days = Math.floor((difference % (1000 * 60 * 60 * 24 * 365.25)) / (1000 * 60 * 60 * 24));
      const hours = Math.floor((difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
      const minutes = Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60));
      const seconds = Math.floor((difference % (1000 * 60)) / 1000);

      setTimeLeft({ years, days, hours, minutes, seconds });
    };

    calculateTime();
    const interval = setInterval(calculateTime, 1000);

    return () => clearInterval(interval);
  }, [deathDate]);

  if (!timeLeft) return <div className="h-64 flex items-center justify-center text-gray-500">Synchronizing...</div>;

  const percentageLeft = Math.max(0, Math.min(100, (totalSecondsLeft / (profile.lifeExpectancyYears * 365.25 * 24 * 3600)) * 100));

  return (
    <div className="w-full flex flex-col items-center py-10">
      <div className="relative group cursor-default">
         {/* Glow Effect */}
        <div className="absolute -inset-4 bg-[#7DF9FF]/20 rounded-full blur-3xl opacity-20 group-hover:opacity-40 transition-opacity duration-700"></div>

        <div className="relative text-center space-y-2">
          <div className="text-gray-500 text-sm uppercase tracking-[0.3em] mb-4">Time Remaining</div>

          <div className="flex flex-wrap justify-center items-baseline gap-4 md:gap-8 font-mono text-[#EAEAEA]">
            <div className="flex flex-col items-center">
              <span className="text-5xl md:text-7xl font-bold tracking-tight drop-shadow-[0_0_10px_rgba(255,255,255,0.3)]">
                {String(timeLeft.years).padStart(2, '0')}
              </span>
              <span className="text-xs text-gray-500 mt-2">YEARS</span>
            </div>
            <div className="flex flex-col items-center">
              <span className="text-5xl md:text-7xl font-bold tracking-tight drop-shadow-[0_0_10px_rgba(255,255,255,0.3)]">
                {String(timeLeft.days).padStart(3, '0')}
              </span>
              <span className="text-xs text-gray-500 mt-2">DAYS</span>
            </div>
          </div>

          <div className="flex justify-center items-center gap-2 md:gap-4 mt-4 font-mono text-[#7DF9FF] text-2xl md:text-4xl font-bold opacity-90">
            <span>{String(timeLeft.hours).padStart(2, '0')}</span>
            <span className="animate-pulse">:</span>
            <span>{String(timeLeft.minutes).padStart(2, '0')}</span>
            <span className="animate-pulse">:</span>
            <span>{String(timeLeft.seconds).padStart(2, '0')}</span>
          </div>
        </div>
      </div>

      {/* Life Progress Bar */}
      <div className="w-full max-w-md mt-12 space-y-2">
        <div className="flex justify-between text-xs text-gray-500 font-mono">
          <span>BIRTH</span>
          <span>{percentageLeft.toFixed(4)}% LEFT</span>
          <span>END</span>
        </div>
        <div className="h-1 w-full bg-white/10 rounded-full overflow-hidden">
          <div 
            className="h-full bg-[#7DF9FF] shadow-[0_0_10px_#7DF9FF]" 
            style={{ width: `${100 - percentageLeft}%`, transition: 'width 1s linear' }}
          ></div>
        </div>
      </div>
    </div>
  );
};

export default LifeClock;

import React, { useState } from 'react';
import { analyzeDailyLog } from '../services/geminiService';
import { StorageService } from '../services/storageService';
import { DailyLog as DailyLogType, UserProfile } from '../types';
import { Send, Loader2, ArrowUp, ArrowDown, Minus } from 'lucide-react';

interface Props {
  onUpdate: (profile: UserProfile) => void;
}

const DailyLog: React.FC<Props> = ({ onUpdate }) => {
  const [input, setInput] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [lastResult, setLastResult] = useState<DailyLogType | null>(null);

  const handleAnalyze = async () => {
    if (!input.trim() || isAnalyzing) return;

    setIsAnalyzing(true);
    setLastResult(null);

    try {
      // 1. Get AI Analysis
      const analysis = await analyzeDailyLog(input);

      // 2. Create Log Object
      const newLog: DailyLogType = {
        id: Date.now().toString(),
        timestamp: new Date().toISOString(),
        content: input,
        timeDeltaSeconds: analysis.timeDeltaSeconds,
        reasoning: analysis.reasoning,
        category: analysis.category as any,
      };

      // 3. Save Log
      StorageService.saveLog(newLog);

      // 4. Update User Profile
      const updatedProfile = StorageService.updateAccumulatedTime(newLog.timeDeltaSeconds);
      if (updatedProfile) {
        onUpdate(updatedProfile);
      }

      setLastResult(newLog);
      setInput('');

    } catch (error) {
      console.error("Failed to process log", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="w-full max-w-xl bg-white/5 border border-white/10 rounded-2xl p-6 backdrop-blur-sm shadow-xl mt-8">
      <h3 className="text-xl font-semibold text-white mb-4">Daily Existence Audit</h3>

      {!lastResult ? (
        <div className="relative">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="How did you spend your existence today? (e.g., Read a book for 2 hours, or Doomscrolled on TikTok...)"
            className="w-full bg-black/40 border border-white/10 rounded-xl p-4 text-gray-200 placeholder-gray-600 focus:outline-none focus:border-[#7DF9FF] focus:ring-1 focus:ring-[#7DF9FF] h-32 resize-none transition-all"
          />
          <div className="absolute bottom-4 right-4">
            <button
              onClick={handleAnalyze}
              disabled={!input.trim() || isAnalyzing}
              className={`p-3 rounded-lg flex items-center justify-center transition-all ${
                input.trim() && !isAnalyzing
                  ? 'bg-[#EAEAEA] text-black hover:bg-white hover:scale-105'
                  : 'bg-white/10 text-gray-500 cursor-not-allowed'
              }`}
            >
              {isAnalyzing ? (
                <Loader2 className="w-5 h-5 animate-spin" />
              ) : (
                <Send className="w-5 h-5" />
              )}
            </button>
          </div>
        </div>
      ) : (
        <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className={`p-4 rounded-xl border mb-4 flex items-start gap-4 ${
            lastResult.timeDeltaSeconds > 0 ? 'bg-green-500/10 border-green-500/30' : 
            lastResult.timeDeltaSeconds < 0 ? 'bg-red-500/10 border-red-500/30' : 
            'bg-gray-500/10 border-gray-500/30'
          }`}>
            <div className={`p-2 rounded-full ${
              lastResult.timeDeltaSeconds > 0 ? 'bg-green-500/20 text-green-400' : 
              lastResult.timeDeltaSeconds < 0 ? 'bg-red-500/20 text-red-400' : 
              'bg-gray-500/20 text-gray-400'
            }`}>
              {lastResult.timeDeltaSeconds > 0 ? <ArrowUp className="w-6 h-6" /> : 
               lastResult.timeDeltaSeconds < 0 ? <ArrowDown className="w-6 h-6" /> : 
               <Minus className="w-6 h-6" />}
            </div>
            <div>
              <div className="font-mono text-lg font-bold flex items-center gap-2">
                {lastResult.timeDeltaSeconds > 0 ? '+' : ''}
                {lastResult.timeDeltaSeconds} SECONDS
                <span className="text-xs font-normal opacity-70 ml-2">
                  ({(lastResult.timeDeltaSeconds / 60).toFixed(1)} min)
                </span>
              </div>
              <p className="text-sm mt-1 text-gray-300 italic">"{lastResult.reasoning}"</p>
            </div>
          </div>
          <button 
            onClick={() => setLastResult(null)}
            className="text-sm text-gray-500 hover:text-[#7DF9FF] underline decoration-dotted"
          >
            Log another entry
          </button>
        </div>
      )}
    </div>
  );
};

export default DailyLog;

import React, { useState, useEffect } from 'react';
import { StorageService } from '../services/storageService';
import { BucketItem, UserProfile } from '../types';
import { Plus, Check, Trash2, Award } from 'lucide-react';

interface Props {
  onUpdate: (profile: UserProfile) => void;
}

const BucketList: React.FC<Props> = ({ onUpdate }) => {
  const [items, setItems] = useState<BucketItem[]>([]);
  const [newItemText, setNewItemText] = useState('');

  useEffect(() => {
    setItems(StorageService.getBucketList());
  }, []);

  const addItem = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newItemText.trim()) return;

    const item: BucketItem = {
      id: Date.now().toString(),
      content: newItemText,
      completed: false,
      rewardSeconds: 259200 // 3 days
    };

    StorageService.saveBucketItem(item);
    setItems([...items, item]);
    setNewItemText('');
  };

  const toggleItem = (id: string) => {
    const item = items.find(i => i.id === id);
    if (!item || item.completed) return; // Cannot uncheck for MVP simplification regarding time math

    const confirm = window.confirm("Did you really complete this? You will gain 3 days of life.");
    if (!confirm) return;

    const updatedItem = { ...item, completed: true, completedAt: new Date().toISOString() };
    StorageService.updateBucketItem(updatedItem);

    // Update local state
    setItems(items.map(i => i.id === id ? updatedItem : i));

    // Update Profile Time
    const updatedProfile = StorageService.updateAccumulatedTime(updatedItem.rewardSeconds);
    if (updatedProfile) onUpdate(updatedProfile);
  };

  return (
    <div className="w-full max-w-xl mt-8">
      <h3 className="text-xl font-semibold text-white mb-4 flex items-center gap-2">
        <Award className="text-[#7DF9FF] w-5 h-5" />
        Meaning List
      </h3>

      <div className="space-y-3">
        {items.map(item => (
          <div 
            key={item.id}
            className={`flex items-center justify-between p-4 rounded-xl border transition-all ${
              item.completed 
                ? 'bg-green-900/10 border-green-500/20 opacity-60' 
                : 'bg-white/5 border-white/10 hover:border-[#7DF9FF]/50'
            }`}
          >
            <span className={`text-sm md:text-base ${item.completed ? 'line-through text-gray-500' : 'text-gray-200'}`}>
              {item.content}
            </span>

            <button
              onClick={() => toggleItem(item.id)}
              disabled={item.completed}
              className={`ml-4 p-2 rounded-full border transition-all ${
                item.completed 
                  ? 'bg-green-500 text-white border-green-500' 
                  : 'border-white/20 text-transparent hover:border-[#7DF9FF] hover:text-[#7DF9FF]'
              }`}
            >
              <Check className="w-4 h-4" />
            </button>
          </div>
        ))}

        <form onSubmit={addItem} className="relative mt-4">
          <input
            type="text"
            value={newItemText}
            onChange={(e) => setNewItemText(e.target.value)}
            placeholder="Add a life goal (Reward: +3 Days)"
            className="w-full bg-black/40 border border-white/10 rounded-xl py-3 pl-4 pr-12 text-sm text-white focus:outline-none focus:border-[#7DF9FF]"
          />
          <button 
            type="submit"
            className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 bg-[#EAEAEA] text-black rounded-lg hover:bg-white"
          >
            <Plus className="w-4 h-4" />
          </button>
        </form>
      </div>
    </div>
  );
};

export default BucketList;

import React, { useState, useEffect } from 'react';
import ParticleBackground from './components/ParticleBackground';
import Onboarding from './components/Onboarding';
import LifeClock from './components/LifeClock';
import DailyLog from './components/DailyLog';
import BucketList from './components/BucketList';
import { StorageService } from './services/storageService';
import { UserProfile, AppView } from './types';
import { Activity, Menu } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<AppView | null>(null);
  const [profile, setProfile] = useState<UserProfile | null>(null);

  useEffect(() => {
    // Check if user exists
    const existingProfile = StorageService.getProfile();
    if (existingProfile) {
      setProfile(existingProfile);
      setView(AppView.DASHBOARD);
    } else {
      setView(AppView.ONBOARDING);
    }
  }, []);

  const handleOnboardingComplete = (newProfile: UserProfile) => {
    setProfile(newProfile);
    setView(AppView.DASHBOARD);
  };

  const handleProfileUpdate = (updatedProfile: UserProfile) => {
    setProfile(updatedProfile);
  };

  if (view === null) return null; // Loading state

  return (
    <div className="relative min-h-screen text-[#EAEAEA] selection:bg-[#7DF9FF] selection:text-black">
      <ParticleBackground />

      {view === AppView.ONBOARDING && (
        <Onboarding onComplete={handleOnboardingComplete} />
