    setView(AppView.DASHBOARD);
  };

  const handleProfileUpdate = (updatedProfile: UserProfile) => {
    setProfile(updatedProfile);
  };

  const handleLogout = async () => {
    await AuthService.signOut();
    setUser(null);
    setProfile(null);
    setView(AppView.AUTH);
  };

  if (view === null) return null; // Loading state

  return (
    <div className="relative min-h-screen text-[#EAEAEA] selection:bg-[#7DF9FF] selection:text-black">
      <ParticleBackground />

      {view === AppView.AUTH && (
        <Auth onAuthSuccess={handleAuthSuccess} />
      )}

      {view === AppView.ONBOARDING && user && (
        <Onboarding user={user} onComplete={handleOnboardingComplete} />
      )}

      {view === AppView.DASHBOARD && profile && (
        <div className="container mx-auto px-4 py-8 pb-20 flex flex-col items-center max-w-4xl animate-in fade-in duration-700">

          {/* Header */}
          <header className="w-full flex justify-between items-center mb-8 border-b border-white/10 pb-4">
            <div className="flex items-center gap-2">
              <Activity className="w-6 h-6 text-[#7DF9FF]" />
              <span className="font-bold tracking-tight text-xl">Still Alive</span>
            </div>
            <div className="flex items-center gap-4">
              <div className="text-sm text-gray-400 font-mono hidden md:block">
                {profile.name}
              </div>
              <button 
                onClick={handleLogout}
                className="p-2 hover:bg-white/10 rounded-full transition-colors text-gray-500 hover:text-white"
                title="Sign Out"
              >
                <LogOut className="w-5 h-5" />
              </button>
            </div>
          </header>

          {/* Main Clock */}
          <LifeClock profile={profile} />

          {/* Interaction Area */}
          <div className="w-full grid grid-cols-1 md:grid-cols-2 gap-8 mt-12">
            <div className="flex flex-col items-center">
               <DailyLog profile={profile} onUpdate={handleProfileUpdate} />
            </div>
            <div className="flex flex-col items-center">
              <BucketList profile={profile} onUpdate={handleProfileUpdate} />
            </div>
          </div>

          <footer className="mt-20 text-xs text-gray-600 text-center">
            <p>Memento Mori. Memento Vivere.</p>
          </footer>
        </div>
      )}
    </div>
  );
};

export default App;

import { AuthUser } from '../types';

const STORAGE_KEY_USER = 'stillalive_current_user';

// Simulating a backend auth service
export const AuthService = {
  // Check if a user is currently "logged in" (persisted session)
  getCurrentUser: (): AuthUser | null => {
    const data = localStorage.getItem(STORAGE_KEY_USER);
    return data ? JSON.parse(data) : null;
  },

  // Simulate Sign In
  signIn: async (email: string): Promise<AuthUser> => {
    // In a real app, verify password here.
    // For this demo, we create a deterministic UID based on email.
    const uid = btoa(email.toLowerCase()).substring(0, 12); 
    const user: AuthUser = { uid, email };

    // Simulate network delay
    await new Promise(resolve => setTimeout(resolve, 800));

    localStorage.setItem(STORAGE_KEY_USER, JSON.stringify(user));
    return user;
  },

  // Simulate Sign Up
  signUp: async (email: string): Promise<AuthUser> => {
    return AuthService.signIn(email);
  },

  // Simulate Social Provider Sign In
  signInWithProvider: async (provider: string): Promise<AuthUser> => {
    // Simulate network delay for OAuth redirect/popup feel
    await new Promise(resolve => setTimeout(resolve, 1200));

    const email = `${provider.toLowerCase()}.nomad@stillalive.app`;
    // Create a UID
    const uid = `social_${provider}_${Date.now().toString(36)}`;

    const user: AuthUser = { uid, email };

    localStorage.setItem(STORAGE_KEY_USER, JSON.stringify(user));
    return user;
  },

  signOut: async (): Promise<void> => {
    localStorage.removeItem(STORAGE_KEY_USER);
  }
};

import React, { useState } from 'react';
import { AuthUser } from '../types';
import { AuthService } from '../services/authService';
import { Lock, Mail, ArrowRight, Loader2, Apple } from 'lucide-react';

interface Props {
  onAuthSuccess: (user: AuthUser) => void;
}

const Auth: React.FC<Props> = ({ onAuthSuccess }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email || !password) return;

    setIsLoading(true);
    try {
      // Simulate Auth
      const user = isLogin 
        ? await AuthService.signIn(email) 
        : await AuthService.signUp(email);

      onAuthSuccess(user);
    } catch (error) {
      console.error("Auth failed", error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSocialLogin = async (provider: string) => {
    if (isLoading) return;
    setIsLoading(true);
    try {
      const user = await AuthService.signInWithProvider(provider);
      onAuthSuccess(user);
    } catch (error) {
      console.error("Social Auth failed", error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-[80vh] px-4 animate-in fade-in duration-700">
      <div className="w-full max-w-md bg-white/5 border border-white/10 rounded-2xl p-8 backdrop-blur-md shadow-2xl">
        <div className="text-center mb-8">
          <h2 className="text-2xl font-bold text-white tracking-tight mb-2">
            {isLogin ? 'Resume Existence' : 'Initiate Life Clock'}
          </h2>
          <p className="text-gray-400 text-sm">
            Secure your timeline. Sync across dimensions.
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-2">
            <label className="text-xs font-mono text-gray-500 uppercase">Identity</label>
            <div className="relative">
              <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500" />
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="email@example.com"
                className="w-full bg-black/40 border border-white/10 rounded-lg pl-10 pr-4 py-3 text-white focus:outline-none focus:border-[#7DF9FF] transition-colors"
                required
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-xs font-mono text-gray-500 uppercase">Access Code</label>
            <div className="relative">
              <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500" />
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="••••••••"
                className="w-full bg-black/40 border border-white/10 rounded-lg pl-10 pr-4 py-3 text-white focus:outline-none focus:border-[#7DF9FF] transition-colors"
                required
              />
            </div>
          </div>

          <button
            type="submit"
            disabled={isLoading}
            className="w-full mt-6 bg-[#EAEAEA] hover:bg-white text-black font-bold py-3 px-6 rounded-lg flex items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-50"
          >
            {isLoading ? <Loader2 className="animate-spin w-4 h-4" /> : (isLogin ? 'Sign In' : 'Create Account')}
            {!isLoading && <ArrowRight className="w-4 h-4" />}
          </button>
        </form>

        <div className="my-6 flex items-center gap-4">
          <div className="h-px bg-white/10 flex-1"></div>
          <span className="text-xs text-gray-500 font-mono">OR CONTINUE WITH</span>
          <div className="h-px bg-white/10 flex-1"></div>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <button 
            onClick={() => handleSocialLogin('Google')} 
            disabled={isLoading}
            className="flex items-center justify-center gap-2 py-2.5 rounded-lg bg-white/5 border border-white/10 hover:bg-white/10 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
          >
             <svg className="w-4 h-4" viewBox="0 0 24 24" fill="white"><path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/><path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/><path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/><path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/></svg>
