          <button 
            onClick={() => setIsLogin(!isLogin)}
            className="text-xs text-gray-500 hover:text-[#7DF9FF] transition-colors"
          >
            {isLogin ? "Need to start a new life? Sign up." : "Already have an existence? Sign in."}
          </button>
        </div>
      </div>
    </div>
  );
};

export default Auth;
